import{c as u,Z as a,Q as d,j as l,g as t,n as s,o,m as n,av as c}from"./chunks/framework.BPKcPtvA.js";const _=JSON.parse('{"title":"Pause / kill-switch via MCP","description":"Pause the agent and revoke its on-chain signing rights from your own LLM, plus session status and audit export.","frontmatter":{"title":"Pause / kill-switch via MCP","description":"Pause the agent and revoke its on-chain signing rights from your own LLM, plus session status and audit export."},"headers":[],"relativePath":"guide/mcp/pause.md","filePath":"guide/mcp/pause.md","lastUpdated":1780199385000}'),g={name:"guide/mcp/pause.md"};function h(p,e,m,y,f,k){const i=a("TaskMeta"),r=a("ExpectedResult");return d(),l("div",null,[e[1]||(e[1]=t("h1",{id:"pause-kill-switch-via-mcp",tabindex:"-1"},[s("Pause / kill-switch via MCP "),t("a",{class:"header-anchor",href:"#pause-kill-switch-via-mcp","aria-label":'Permalink to "Pause / kill-switch via MCP"'},"​")],-1)),o(i,{time:"~2 min",role:"Investor",needs:"@muhaven/mcp logged in (M1), an active session to pause"}),e[2]||(e[2]=n('<blockquote><p><strong>What you&#39;ll do:</strong> hit the panic button from your own LLM — pause the agent, check session status, and export the audit log.</p></blockquote><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Prerequisites</p><p>The <code>@muhaven/mcp</code> server logged in (<a href="/guide/mcp/install">M1</a>), with an active agent session to stop. This is the MCP twin of <a href="/guide/agent/pause">H6 · Pause / kill-switch</a> and <a href="/guide/agent/session-audit">H7 · Session status + audit</a>.</p></div><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>In your host, type <strong>&quot;Pause my muhaven agent.&quot;</strong> → <code>muhaven.policy.pause</code>. <ul><li><strong>Omit the surface</strong> to cascade the pause across <strong>all</strong> agent surfaces; pass one to pause just that surface.</li><li>The surface is marked <strong>Paused</strong> immediately, and the tool returns an <strong>unsigned UserOp</strong> that uninstalls the agent&#39;s on-chain validator. Submit it with your <strong>passkey</strong> — signing rights are gone in <strong>≤1 Arbitrum block</strong>.</li></ul></li><li>Ask <strong>&quot;What&#39;s my agent session status?&quot;</strong> → <code>muhaven.policy.session_key_status</code> — returns tier, validator address, valid-until, recent action count.</li><li>Ask <strong>&quot;Export my agent audit log.&quot;</strong> → <code>muhaven.policy.audit_export</code> — streams your full tiered-autonomy log as one JSON document.</li><li><strong>To resume</strong>, pick <strong>Advisory</strong> on the dashboard (<code>/agent/policy/transition</code> → <strong>Resume to Advisory</strong>) — there is no MCP <code>resume</code> tool.</li></ol><p>::: important The panic button <code>pause</code> marks the surface Paused instantly; submitting the returned UserOp with your passkey is what actually revokes the agent&#39;s signing rights on-chain. :::</p><h2 id="expected-result" tabindex="-1">Expected result <a class="header-anchor" href="#expected-result" aria-label="Permalink to &quot;Expected result&quot;">​</a></h2>',7)),o(r,null,{default:c(()=>[...e[0]||(e[0]=[t("code",null,"muhaven.policy.pause",-1),s(" marks the surface ",-1),t("strong",null,"Paused",-1),s(" immediately and returns an ",-1),t("strong",null,"unsigned UserOp",-1),s("; after you submit it with your passkey the agent's validator is uninstalled in ",-1),t("em",null,"≤1 Arbitrum block",-1),s(". ",-1),t("code",null,"session_key_status",-1),s(" and ",-1),t("code",null,"audit_export",-1),s(" are read-only. ",-1)])]),_:1}),e[3]||(e[3]=n('<h2 id="if-something-goes-wrong" tabindex="-1">If something goes wrong <a class="header-anchor" href="#if-something-goes-wrong" aria-label="Permalink to &quot;If something goes wrong&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Fix</th></tr></thead><tbody><tr><td>Surface shows Paused but the agent still seems active</td><td>Submit the returned <strong>unsigned UserOp</strong> with your passkey to actually revoke signing rights.</td></tr><tr><td><code>session_key_status</code> shows no active session</td><td>You haven&#39;t armed a Scoped session — see <a href="/guide/mcp/set-tier">M5</a>.</td></tr><tr><td>Need to bring the agent back</td><td>Resume needs a passkey — pick <strong>Advisory</strong> on the dashboard (<strong>Resume to Advisory</strong>); there is no MCP <code>resume</code> tool.</td></tr></tbody></table><p>→ Next: <a href="/guide/reference">Reference appendix</a></p>',3))])}const v=u(g,[["render",h]]);export{_ as __pageData,v as default};
